#!/bin/bash

# Rename a benchmark generated by Aetherling.
#
# Arguments:
#  $1: the benchmark to rename.

set -ue

function get_new_name {
    echo "$1" |
        # Use _ rather than % and avoid spaces
        sed 's/ % /_/g' |
        # No need for the trailing "thr"
        sed 's/thr//g' |
        # No need for denominator if it's 1
        sed -E 's/_([0-9]+)_1\./_\1\./g'
}

function rename_bench {
    local f; f="$1"
    local new_name; new_name="$(get_new_name "$f")"
    if [[ "$f" != "$new_name" ]]; then
        mv "$f" "$new_name"
    fi
}

rename_bench "$1"
